import { LitElement } from 'lit';
import { labelsService, type SupportedLocale, type IComponentLabels } from './labels-service.js';

/**
 * Configuration for translatable component
 */
export interface ITranslatableConfig<TLabels extends IComponentLabels> {
  translations: Record<SupportedLocale, TLabels>;
  deprecatedPropsMap: Record<string, keyof TLabels>;
  component: LitElement;
  labelsOverride?: Partial<TLabels>;
}

/**
 * Gets computed labels with 3-tier priority system:
 * 1. Deprecated individual props (backward compatibility)
 * 2. Labels object prop (user override)
 * 3. Locale-based translations
 *
 * @param config - Configuration object
 * @returns Computed labels
 */
export function getComputedLabels<TLabels extends IComponentLabels>(
  config: ITranslatableConfig<TLabels>,
): Required<TLabels> {
  const { translations, deprecatedPropsMap, component, labelsOverride } = config;
  const currentLocale = labelsService.getCurrentLocale();
  const localTranslations = translations[currentLocale] || translations.en;

  // Priority 1: Check if any deprecated props were explicitly set
  const deprecatedPropNames = Object.keys(deprecatedPropsMap);
  if (deprecatedPropNames.length > 0) {
    const hasDeprecatedProps = deprecatedPropNames.some((propName) => {
      const componentValue = (component as any)[propName];
      const labelKey = deprecatedPropsMap[propName];
      const defaultValue = (translations.en as any)[labelKey];
      return componentValue !== undefined && componentValue !== defaultValue;
    });

    if (hasDeprecatedProps) {
      const deprecatedLabels = {} as Partial<TLabels>;
      deprecatedPropNames.forEach((propName) => {
        const componentValue = (component as any)[propName];
        const labelKey = deprecatedPropsMap[propName];
        if (componentValue !== undefined) {
          (deprecatedLabels as any)[labelKey] = componentValue;
        }
      });

      return {
        ...localTranslations,
        ...deprecatedLabels,
      } as Required<TLabels>;
    }
  }

  // Priority 2: If labels object is provided, merge with default translations
  if (labelsOverride) {
    return {
      ...localTranslations,
      ...labelsOverride,
    } as Required<TLabels>;
  }

  // Priority 3: Use locale-based translations
  return localTranslations as Required<TLabels>;
}

/**
 * Mixin that adds translation support to components.
 *
 * Note: This mixin adds automatic document.lang change detection.
 * Use this when you want automatic re-rendering when the document language changes.
 *
 * @example
 * ```typescript
 * export class MyComponent extends WithTranslations(MyBaseClass) {
 *   @property({ type: Object })
 *   public labels?: Partial<IMyComponentLabels>;
 *
 *   protected get computedLabels(): Required<IMyComponentLabels> {
 *     return getComputedLabels({
 *       translations,
 *       deprecatedPropsMap: { oldprop: 'newLabel' },
 *       component: this,
 *       labelsOverride: this.labels,
 *     });
 *   }
 * }
 * ```
 */
export function WithTranslations<TBase extends new (...args: any[]) => LitElement>(Base: TBase): TBase {
  // Define a named class to avoid TypeScript declaration errors
  class TranslatableComponent extends Base {
    private langObserver?: MutationObserver;

    /**
     * Request update when document lang changes
     */
    protected handleDocumentLangChange = (): void => {
      this.requestUpdate();
    };

    public override connectedCallback(): void {
      super.connectedCallback();

      // Only set up MutationObserver in browser environment (not SSR)
      if (typeof document !== 'undefined') {
        // Listen for lang attribute changes on document
        this.langObserver = new MutationObserver(this.handleDocumentLangChange);
        this.langObserver.observe(document.documentElement, {
          attributes: true,
          attributeFilter: ['lang'],
        });
      }
    }

    public override disconnectedCallback(): void {
      super.disconnectedCallback();
      this.langObserver?.disconnect();
    }
  }

  return TranslatableComponent as TBase;
}
